param(
    [string]$VcpkgRoot = $env:VCPKG_ROOT,
    [string]$Triplet = $(if ($env:VCPKG_DEFAULT_TRIPLET) { $env:VCPKG_DEFAULT_TRIPLET } else { 'x64-windows' }),
    [string]$InstallRoot = $(Join-Path $PSScriptRoot 'vcpkg_installed')
)

$ErrorActionPreference = 'Stop'

# Generated by scripts/convert-kicad-deps.py.
# Source KiCad version: 10.0.4
# Source KiCad commit: f7414d419cae5df2d00e7eaacb16fc0e803799bc
# Do not edit by hand; rerun scripts/update-kicad-deps.sh.

if (-not $VcpkgRoot) {
    $VcpkgRoot = 'C:\builder\vcpkg'
}

$vcpkgExe = Join-Path $VcpkgRoot 'vcpkg.exe'
if (-not (Test-Path $vcpkgExe)) {
    throw "vcpkg.exe not found. Set VCPKG_ROOT or pass -VcpkgRoot."
}

$manifestRoot = Join-Path $PSScriptRoot '.vcpkg-manifest'
New-Item -ItemType Directory -Force -Path $manifestRoot | Out-Null
@'
{
  "$schema": "https://raw.githubusercontent.com/microsoft/vcpkg-tool/main/docs/vcpkg.schema.json",
  "name": "kicad",
  "version": "8.99",
  "license": "GPL-2.0+",
  "dependencies": [
    "boost-algorithm",
    "boost-bimap",
    "boost-filesystem",
    "boost-functional",
    "boost-iterator",
    "boost-locale",
    "boost-optional",
    "boost-property-tree",
    "boost-ptr-container",
    "boost-random",
    "boost-range",
    "boost-stacktrace",
    "boost-test",
    "boost-uuid",
    "cairo",
    {
      "name": "wxwidgets-33",
      "features": [
        "webview"
      ]
    },
    "curl",
    {
      "name": "gettext",
      "features": [
        "tools"
      ],
      "host": true
    },
    "harfbuzz",
    "glm",
    {
      "name": "opencascade",
      "features": [
        "rapidjson"
      ]
    },
    "opengl",
    "python3",
    "openssl",
    {
      "name": "sqlite3",
      "features": [
        "fts5",
        "fts4",
        "fts3",
        "rtree",
        "session"
      ]
    },
    "icu",
    "ngspice",
    "wxpython-33",
    {
      "name": "libgit2",
      "features": [
        "ssh",
        "winhttp"
      ]
    },
    "nng",
    "protobuf",
    "zstd"
  ],
  "overrides": [
    {
      "name": "glm",
      "version": "0.9.9.8#2",
      "$comment": "Pinned due to bad vcpkg port updating to a non-real version"
    },
    {
      "name": "python3",
      "version": "3.11.5#0"
    },
    {
      "name": "wxwidgets-33",
      "version": "3.3.1#4"
    },
    {
      "name": "wxpython-33",
      "version": "4.2.3#6"
    },
    {
      "name": "ngspice",
      "version": "46#0"
    },
    {
      "name": "protobuf",
      "version": "3.21.12#4",
      "$comment": "Pinned until compat in kicad is improved"
    }
  ]
}
'@ | Set-Content -Encoding utf8 -Path (Join-Path $manifestRoot 'vcpkg.json')

& $vcpkgExe install `
    --x-manifest-root=$manifestRoot `
    --triplet=$Triplet `
    --x-install-root=$InstallRoot `
    --x-abi-tools-use-exact-versions
